const [retrying, setRetrying] = useState<Set<string>>(new Set());
const retrySend = (cid: string, text: string) => {
  if (retrying.has(cid)) return;
  setRetrying((s) => new Set(s).add(cid));
  void store.postMessage({ roomId, channel, author: me, text, clientMsgId: cid, kind: "chat" })
    .then((fb) => { if (fb && fb.ok) setFailedSends((f) => f.filter((x) => x.cid !== cid)); })
    .finally(() => setRetrying((s) => { const n = new Set(s); n.delete(cid); return n; }));
};
// button:
<button className={"r-msg-act promote" + (retrying.has(f.cid) ? " r-busy" : "")} disabled={retrying.has(f.cid)} data-testid="chat-retry" onClick={() => retrySend(f.cid, f.text)}><RefreshCw size={12} /> {retrying.has(f.cid) ? "Retrying…" : "Retry"}</button>
